import { awbGenerationService } from "./AWBGenerationService";

export async function fetchAWBPartyConf(pageNumber, recordPerPage) {
    let response = await awbGenerationService.fetchAWBPartyConf(pageNumber, recordPerPage);
    return response;
}

export async function searchAWBPartyListByPartyCode(partyCodes,pageNumber, recordPerPage) {
    let response = await awbGenerationService.searchAWBPartyListByPartyCode(partyCodes,pageNumber, recordPerPage);
    return response;
}

export async function fetchAWBDefaultDetails() {
    let response = await awbGenerationService.fetchAWBDefaultDetails();
    return response;
}

export async function saveAWBDefaultDetails(awbDefaultDetails) {
    let response = await awbGenerationService.saveAWBDefaultDetails(awbDefaultDetails);
    return response;
}

export async function saveAWBPartyConf(awbPartyConf) {
    let response = await awbGenerationService.saveAWBPartyConf(awbPartyConf);
    return response;
}

export async function deleteAWBPartyConf(id) {
    let response = await awbGenerationService.deleteAWBPartyConf(id);
    return response;
}

export async function fetchAllPartyMaster() {
    let response = await awbGenerationService.fetchAllPartyMaster();
    return response;
}
